/* Postgres example: create index, check plan */
CREATE INDEX users_email_idx ON users (email);
ANALYZE users;
EXPLAIN ANALYZE SELECT id, name FROM users WHERE email = 'alice@example.com';

/* Composite and partial examples */
CREATE INDEX idx_users_country_created ON users (country, created_at DESC);
CREATE INDEX idx_orders_active_userid ON orders (user_id) WHERE status = 'active';
